ruleContent.content:
@js:
var doc = org.jsoup.Jsoup.parse(result);
var list = [];

// 1. 获取所有图片详情页链接（严格按照你指定的路径）
var links = doc.select("#bodywrap > div.grid > div > ul > li div.pic_box.tb > a");

if (links.size() === 0) {
    links = doc.select("#bodywrap div.grid li a, div.cc li a, div.grid li a");
}

var checkId = 't3';

// 2. 尝试提取子域名
if (links.size() > 0) {
    var firstHref = links.get(0).attr("href");
    if (firstHref) {
        if (!firstHref.startsWith("http")) firstHref = "https://www.wnacg.com" + firstHref;
        try {
            var firstPage = java.ajax(firstHref);
            var firstDoc = org.jsoup.Jsoup.parse(firstPage);
            var picSrc = firstDoc.select("#picarea").first();
            if (picSrc != null) {
                var m = picSrc.attr("src").match(/\/\/(\w+?)\.wnacg/);
                if (m) checkId = m[1];
            }
        } catch(e) {}
    }
}

// 3. 遍历所有链接，打开页面提取 #picarea
for (var i = 0; i < links.size(); i++) {
    var href = links.get(i).attr("href");
    if (!href) continue;

    if (!href.startsWith("http")) {
        href = "https://www.wnacg.com" + href;
    }

    try {
        var pageHtml = java.ajax(href);
        var pageDoc = org.jsoup.Jsoup.parse(pageHtml);
        var picarea = pageDoc.select("#picarea").first();

        if (picarea != null) {
            var realSrc = picarea.attr("src");
            if (realSrc) {
                if (!realSrc.startsWith("http")) {
                    realSrc = "https:" + (realSrc.startsWith("//") ? realSrc : "//" + realSrc);
                }
                list.push('<img src="' + realSrc + '">');
            }
        }
    } catch (e) {
        java.log("第" + (i+1) + "张加载失败: " + e);
    }
}

// 4. 兜底逻辑（兼容老漫画）
if (list.length === 0) {
    var names = doc.select("div.title span.name");
    if (names.size() > 0) {
        var timeMatch = doc.text().match(/(\d{4})-(\d{2})/);
        var year = timeMatch ? timeMatch[1] : '2020';
        var month = timeMatch ? timeMatch[2] : '01';
        var path = '/' + year + '/' + month + '/';

        for (var j = 0; j < names.size(); j++) {
            var fname = names.get(j).text().trim();
            if (fname) {
                list.push('<img src="https://' + checkId + '.wnacg.com/data' + path + fname + '.jpg">');
            }
        }
    }
}

result = list.join('');
if (result === '') {
    result = '<p>图片解析失败，建议尝试目录中的「第1页」或「下拉连续阅读」</p>';
}

