function getCover(html) {
    var h = String(html);
    var m = h.match(/url\(['"]?([^'"()]+)['"]?\)/);
    if (m) return m[1];
    var m2 = h.match(/data-src=["']([^"']+)["']/);
    return m2 ? m2[1] : '';
}

