@js:
function secret(data, code) {
    code = java.md5Encode(code);
    iv = code.slice(0, 16);
    key = code.slice(16);
    return java.createSymmetricCrypto("AES/CBC/PKCS7Padding", key, iv).decryptStr(data);
}

let match = src.match(/var chapter = secret\(['"](.+?)['"],\s*['"](.+?)['"].*\)/);
if (match) {
    result = secret(match[1], match[2]);
}

ruleToc.chapterList:
li!0@a
@js:
let elements = org.jsoup.Jsoup.parse(result).select("a");
let dataList = [];
elements.forEach(element => {
    let href = element.attr("href");
    if (href.includes("javascript")) {
        href = eval(String(href));
    }
    let text = element.text();
    let match = href.match(/(\d+)\.html/);
    if (match) {
        dataList.push({
            href: href,
            cid: parseInt(match[1]),
            text: text
        });
    }
});

dataList.sort((a, b) => a.cid - b.cid);

